# Wait for completion
while [ "$(curl -s "$BASE/scans/$SCAN_ID" -H "Authorization: Bearer $API_KEY" | jq -r '.status')" != "completed" ]; do
  sleep 30
done

# Get findings
curl -s "$BASE/findings/scan/$SCAN_ID" -H "Authorization: Bearer $API_KEY" | jq '.data[]'
